 1	import React, { MouseEvent, useEffect, useState } from 'react';
 2	
 3	import { NetworkAttachmentDefinitionModelGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 4	import FormPFSelect from '@kubevirt-utils/components/FormPFSelect/FormPFSelect';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { getName } from '@kubevirt-utils/resources/shared';
 7	import { isEmpty } from '@kubevirt-utils/utils/utils';
 8	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 9	import {
10	  Alert,
11	  AlertVariant,
12	  SelectGroup,
13	  SelectOption,
14	  Skeleton,
15	  Text,
16	  TextVariants,
17	  Title,
18	} from '@patternfly/react-core';
19	
20	import { NetworkAttachmentDefinitionKind } from '../../../../../../OverviewTab/inventory-card/utils/types';
21	import {
22	  getLiveMigrationNetwork,
23	  PRIMARY_NETWORK,
24	  updateLiveMigrationConfig,
25	} from '../utils/utils';
26	
27	const Network = ({ hyperConverge }) => {
28	  const { t } = useKubevirtTranslation();
29	  const [selectedNetwork, setSelectedNetwork] = useState<string>('');
30	  const [nads, nadsLoaded, nadsError] = useK8sWatchResource<NetworkAttachmentDefinitionKind[]>({
31	    groupVersionKind: NetworkAttachmentDefinitionModelGroupVersionKind,
32	    isList: true,
33	  });
34	
35	  useEffect(() => {
36	    if (hyperConverge) {
37	      const network = getLiveMigrationNetwork(hyperConverge);
38	      setSelectedNetwork(network ?? PRIMARY_NETWORK);
39	    }
40	  }, [hyperConverge]);
41	
42	  const onSelect = (_event: MouseEvent<Element>, selectedValue: string) => {
43	    updateLiveMigrationConfig(
44	      hyperConverge,
45	      selectedValue !== PRIMARY_NETWORK ? selectedValue : null,
46	      'network',
47	    );
48	    setSelectedNetwork(selectedValue);
49	  };
50	  return (
51	    <>
52	      <Text component={TextVariants.small}>{t('Set live migration network')}</Text>
53	      <Title className="live-migration-tab__network--title" headingLevel="h6" size="md">
54	        {t('Live migration network')}
55	      </Title>
56	      {nadsLoaded ? (
57	        <FormPFSelect
58	          onSelect={onSelect}
59	          popperProps={{ width: '360px' }}
60	          selected={selectedNetwork}
61	          toggleProps={{ isDisabled: isEmpty(nads) }}
62	        >
63	          <SelectOption key="primary" value={PRIMARY_NETWORK}>
64	            {t('Primary live migration network')}
65	          </SelectOption>
66	          <SelectGroup key="nad" label={t('Secondary NAD networks')}>
67	            {nads?.map((nad) => {
68	              const nadName = getName(nad);
69	              return (
70	                <SelectOption key={nadName} value={nadName}>
71	                  {nadName}
72	                </SelectOption>
73	              );
74	            })}
75	          </SelectGroup>
76	        </FormPFSelect>
77	      ) : (
78	        !nadsError && <Skeleton width={'360px'} />
79	      )}
80	      {nadsError && (
81	        <Alert
82	          className="live-migration-tab--error"
83	          isInline
84	          title={t('Error')}
85	          variant={AlertVariant.danger}
86	        >
87	          {nadsError?.message}
88	        </Alert>
89	      )}
90	    </>
91	  );
92	};
93	
94	export default Network;

